export declare function getYAxisTickFormatter(scale: ScaleLogarithmic<number, number> | ScaleSymLog<number, number> | ScaleLinear<number, number> | ScaleTime<number, number>, unit?: ChartUnit, formatter?: Formatter, numTicks?: number, precision?: number): TickValueFormatter;
